#ifndef I2S_SPEAKER_H
#define I2S_SPEAKER_H
#include <Arduino.h>
void i2s_spk_setup();
void i2s_spk_write(const int16_t* samples, size_t count);
void i2s_spk_tone(uint16_t freq, uint16_t duration_ms);
void i2s_spk_stop();
