firmware_template.source:
#include "i2s_speaker.h"
#include <driver/i2s.h>
#include <math.h>
#define SPK_BCLK 26
#define SPK_LRC 25
#define SPK_DIN 22
#define SPK_RATE 44100
void i2s_spk_setup() {
  i2s_config_t cfg = {};
  cfg.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX);
  cfg.sample_rate = SPK_RATE;
  cfg.bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT;
  cfg.channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT;
  cfg.communication_format = I2S_COMM_FORMAT_STAND_I2S;
  cfg.dma_buf_count = 8;
  cfg.dma_buf_len = 1024;
  i2s_driver_install(I2S_NUM_1, &cfg, 0, NULL);
  i2s_pin_config_t pins = { .bck_io_num = SPK_BCLK, .ws_io_num = SPK_LRC, .data_out_num = SPK_DIN, .data_in_num = -1 };
  i2s_set_pin(I2S_NUM_1, &pins);
  Serial.println("[i2s_spk] OK 44.1kHz");
}
void i2s_spk_write(const int16_t* s, size_t n) {
  size_t written = 0;
  i2s_write(I2S_NUM_1, s, n * 2, &written, portMAX_DELAY);
}
void i2s_spk_tone(uint16_t freq, uint16_t dur) {
  int samples = SPK_RATE * dur / 1000;
  int16_t buf[256];
  for (int i = 0; i < samples; i += 256) {
    int chunk = (samples - i < 256) ? samples - i : 256;
    for (int j = 0; j < chunk; j++) {
      buf[j] = (int16_t)(sinf(2.0f * 3.14159f * freq * (i+j) / SPK_RATE) * 16000);
    }
    i2s_spk_write(buf, chunk);
  }
}
void i2s_spk_stop() {
  int16_t silence[64] = {0};
  i2s_spk_write(silence, 64);
}
